INSERT INTO persons (uid, name, courtesy_name, dynasty_id, years, years_display, gender, roles, quote, bio, tags, related_events, related_persons) VALUES
('confucius', '孔子', '仲尼', NULL, '[-551, -479]', '公元前551年 — 公元前479年', 'male', '["儒家创始人", "教育家", "思想家"]', '学而时习之，不亦说乎', '孔子名丘字仲尼，儒家学派创始人。一生致力于恢复礼制，周游列国宣扬仁政思想。晚年编订诗书礼乐易春秋，被后世尊为至圣先师。其弟子整理论语，记录孔子及其弟子言行，成为儒家经典。教育上首创私学，主张有教无类因材施教。', '["仁", "义", "礼", "智", "信", "有教无类", "因材施教"]', '["spring-autumn"]', '["mencius", "laozi"]'),
('laozi', '老子', '伯阳', NULL, '[-600, -500]', '约公元前6世纪', 'male', '["道家创始人", "哲学家", "周守藏室之史"]', '道可道，非常道；名可名，非常名', '老子姓李名耳字伯阳，曾为周朝守藏室之史。著有道德经五千言，提出道法自然无为而治的思想。骑青牛出函谷关，留下千古名篇。其思想核心是道，认为道是宇宙万物的本源和规律。', '["道德经", "道法自然", "无为而治", "阴阳辩证"]', '["spring-autumn"]', '["confucius"]'),
('mencius', '孟子', '子舆', NULL, '[-372, -289]', '公元前372年 — 公元前289年', 'male', '["亚圣", "儒家", "政治家", "性善论"]', '民为贵，社稷次之，君为轻', '孟子名轲字子舆，孔子之孙伋的孙子。继承并发扬孔子思想，被称为亚圣。主张性善论，提出仁政学说，强调民本思想。游说诸侯不行仁政，晚年与弟子著书七篇，即孟子。', '["性善论", "仁政", "民本", "养浩然之气"]', '["spring-autumn"]', '["confucius"]'),
('qin-shi', '秦始皇', '', NULL, '[-259, -210]', '公元前259年 — 公元前210年', 'male', '["始皇帝", "统一六国", "中央集权", "千古一帝"]', '朕为始皇帝，后世以计数，二世三世至于万世，传之无穷', '秦始皇嬴政，秦庄襄王之子。十三岁即位，二十二岁亲政，横扫六国完成统一大业。称始皇帝，废分封立郡县，统一文字度量衡货币，修筑万里长城，建立中国历史上第一个大一统中央集权帝国。', '["统一六国", "兵马俑", "长城", "郡县制", "焚书坑儒", "徐福东渡"]', '["qin-unify"]', '[]'),
('tang-taizong', '唐太宗', '', NULL, '[598, 649]', '公元598年 — 649年', 'male', '["千古明君", "贞观之治", "军事家", "政治家"]', '以铜为镜，可以正衣冠；以古为镜，可以知兴替', '唐太宗李世民，唐高祖李渊次子。发动玄武门之变即位，开创贞观之治。任用房玄龄杜如晦魏征等贤臣，虚心纳谏，政治清明。对外开疆拓土，被尊为天可汗。奠定唐朝两百多年基业，被誉为千古明君。', '["贞观之治", "魏征", "房谋杜断", "天可汗", "玄武门之变"]', '["zhenguan-zhi", "tang-dynasty"]', '[]'),
('wu-zetian', '武则天', '', NULL, '[624, 705]', '公元624年 — 705年', 'female', '["女皇帝", "政治家", "文学家", "千古一后"]', '明眸皓齿今何在，血污游魂归不得', '武则天名曌，中国历史上唯一的女皇帝。十四岁入宫为唐太宗才人，后出家感业寺。唐高宗时被封为皇后，逐步掌控朝政。690年称帝建国号为周，改元天授。在位期间发展科举重用人才重视农业生产，为开元盛世奠定基础。', '["女皇帝", "武周", "殿试", "科举", "则天政治"]', '["tang-dynasty"]', '[]'),
('kangxi', '康熙帝', '玄烨', NULL, '[1654, 1722]', '公元1654年 — 1722年', 'male', '["在位61年", "康乾盛世", "勤政爱民", "学者皇帝"]', '治国之要，首在谨几微、慎动静', '康熙帝爱新觉罗·玄烨，清圣祖。八岁登基，在位61年为历代最长。平定三藩收复台湾抗击沙俄三次亲征噶尔丹。重视农业治理黄河编纂康熙字典。开创康乾盛世基业。', '["康乾盛世", "平定三藩", "收复台湾", "抗击沙俄", "康熙字典"]', '["kang-qian-shengshi", "qing-dynasty"]', '[]'),
('libai', '李白', '太白', NULL, '[701, 762]', '公元701年 — 762年', 'male', '["诗仙", "浪漫主义", "酒仙", "剑客"]', '天生我材必有用，千金散尽还复来', '李白字太白号青莲居士，中国历史上最伟大的浪漫主义诗人。幼年随父迁居江油，二十五岁出蜀漫游。曾供奉翰林，后因得罪权贵被赐金放还。一生嗜酒如命，其诗豪放飘逸想象丰富，被誉为诗仙。代表作有将进酒蜀道难梦游天姥吟留别等。', '["诗仙", "浪漫主义", "将进酒", "蜀道难", "月下独酌"]', '["tang-dynasty"]', '[]'),
('dufu', '杜甫', '子美', NULL, '[712, 770]', '公元712年 — 770年', 'male', '["诗圣", "现实主义", "诗史", "草堂主人"]', '安得广厦千万间，大庇天下寒士俱欢颜', '杜甫字子美，祖籍襄阳，生于巩县。中国历史上最伟大的现实主义诗人。一生坎坷，曾任左拾遗。安史之乱中颠沛流离，写下大量反映现实的诗篇，被后世誉为诗史。其诗沉郁顿挫，格律严谨，与李白并称李杜。代表作有春望登高茅屋为秋风所破歌。', '["诗圣", "现实主义", "三吏三别", "春望", "草堂"]', '["tang-dynasty", "an-shi"]', '["libai"]'),
('sushi', '苏轼', '子瞻', NULL, '[1037, 1101]', '公元1037年 — 1101年', 'male', '["全才", "文学家", "书法家", "美食家", "词人"]', '人有悲欢离合，月有阴晴圆缺', '苏轼字子瞻号东坡居士，眉州眉山人。北宋文学巨匠，诗文书画皆精。进士及第后历任多地，因乌台诗案被贬黄州。其词开创豪放一派，与辛弃疾并称苏辛。散文位列唐宋八大家，书法宋四家之一。代表作有赤壁赋水调歌头念奴娇等。', '["东坡", "豪放派", "赤壁赋", "水调歌头", "美食"]', '["song-dynasty"]', '[]'),
('sun-wu', '孙武', '长卿', NULL, '[-540, -480]', '约公元前540年 — 约公元前480年', 'male', '["兵圣", "军事家", "作家", "吴国大将"]', '知己知彼，百战不殆', '孙武字长卿，齐国贵族后裔，后奔吴国。吴王阖闾召见，以孙子十三篇献于吴王，被任为大将。率吴军攻破楚国，北威齐晋，南服越人，辅佐吴王阖闾成就霸业。所著孙子兵法为世界军事史上最早最系统的专著，被译为多国文字，奉为兵圣。', '["孙子兵法", "兵圣", "吴国", "军事理论", "春秋"]', '["spring-autumn"]', '[]'),
('wei-qing', '卫青', '', NULL, '[-203, -106]', '公元前203年 — 前106年', 'male', '["大将军", "军事天才", "民族英雄", "抗击匈奴"]', '匈奴未灭，何以家为', '卫青，河东平阳人，西汉抗匈名将。出身奴隶，以骑郎将侍武帝。七次出击匈奴，收复河套地区，解除匈奴对长安威胁。任大将军，封大司马。一生七战七捷，为汉朝北部疆域开拓立下赫赫战功，与外甥霍去病并称西汉双璧。', '["汉匈战争", "大将军", "漠北之战", "骑术"]', '["han-establish", "wu-di-da-tong"]', '["huo-qubing"]'),
('huo-qubing', '霍去病', '', NULL, '[-140, -117]', '公元前140年 — 前117年', 'male', '["骠骑将军", "少年英雄", "封狼居胥"]', '匈奴未灭，无以家为也', '霍去病，河东平阳人，卫青外甥。十七岁率八百轻骑立功，封冠军侯。二十岁任骠骑将军，六次出击匈奴，歼敌十余万，收复河西走廊。二十二岁漠北之战封狼居胥禅于姑衍，登临瀚海，成为中国历史上最年轻的军事天才。英年早逝，汉武帝为之泣，调遣边郡部队大举哀悼。', '["封狼居胥", "河西之战", "少年英雄", "冠军侯"]', '["wu-di-da-tong", "wei-qing"]', '["wei-qing"]'),
('yue-fei', '岳飞', '鹏举', NULL, '[1103, 1142]', '公元1103年 — 1142年', 'male', '["民族英雄", "军事家", "诗人", "抗金名将"]', '莫等闲，白了少年头，空悲切', '岳飞字鹏举，相州汤阴人。南宋最杰出的抗金将领。出身农家，从军报国。组建岳家军纪律严明，冻死不拆屋饿死不掳掠。屡破金军，收复襄阳六郡，郾城大捷大破金军铁浮屠拐子马。后被秦桧以莫须有罪名害于大理寺风波亭，年仅三十九岁。其子岳云部将张宪同被害。宋孝宗时平反追谥武穆，后改谥忠武。', '["岳家军", "抗金", "满江红", "风波亭", "精忠报国"]', '["jingkang", "song-dynasty"]', '[]'),
('qi-ji-guang', '戚继光', '元敬', NULL, '[1528, 1588]', '公元1528年 — 1588年', 'male', '["抗倭名将", "军事家", "武术家", "民族英雄"]', '封侯非我意，但愿海波平', '戚继光字元敬，号南塘，山东登州人。明朝著名军事家，抗倭英雄。年少袭职，组建戚家军。在东南沿海十年抗倭，台州九战九捷，横屿牛田草寨连战连捷，基本平定浙江福建倭患。后调任广东蓟镇，练兵筑墙，保障北方边境安宁。著纪效新书练兵实纪，为中国古代军事理论重要著作。', '["抗倭", "戚家军", "鸳鸯阵", "纪效新书"]', '["ming-dynasty"]', '[]'),
('zhang-heng', '张衡', '平子', NULL, '[78, 139]', '公元78年 — 139年', 'male', '["天文学家", "发明家", "地理学家", "文学家"]', '天圆如张盖，地方如棋局', '张衡字平子，南阳西鄂人。东汉最伟大的科学家之一。发明了世界上第一台地震探测仪器——候风地动仪，能感知千里之外的地震。又造浑天仪观测天象，著灵宪阐述宇宙理论。文学上著二京赋，与司马相如扬雄并称汉代四大家。官至太史令，精通天文历法数学。', '["地动仪", "浑天仪", "天文学", "地震", "二京赋"]', '["han-establish"]', '[]'),
('zu-chongzhi', '祖冲之', '文远', NULL, '[429, 500]', '公元429年 — 500年', 'male', '["数学家", "天文学家", "工程师", "科学家"]', '割之弥细，所失弥少，割之又割，以至于不可割', '祖冲之字文远，范阳遒县人。中国古代最伟大的数学家之一。将圆周率精确到小数点后第七位（3.1415926至3.1415927之间），这一纪录保持了一千年之久。编制大明历首次引入闰日概念，改进圭表测量日影。又著缀术，创制千里船水上碓磨等机械。', '["圆周率", "大明历", "数学", "天文", "几何"]', '["bei-wei-huaibei"]', '[]'),
('bi-sheng', '毕昇', '', NULL, '[970, 1051]', '约公元970年 — 约1051年', 'male', '["发明家", "刻字工", "活字印刷术创始人"]', '活字之法，肇自宋毕昇', '毕昇，北宋淮南人。中国活字印刷术发明者。在雕版印刷基础上创造性地发明了胶泥活字印刷术，用胶泥刻字火烧硬化，排版时按韵排列，一板印刷完拆下活字下次再用。极大提高了印刷效率降低了成本。沈括梦溪笔谈详细记载了其发明过程。比欧洲古腾堡活字印刷早约四百年。', '["活字印刷", "泥活字", "印刷术", "沈括", "梦溪笔谈"]', '["song-dynasty"]', '["shen-kuo"]'),
('shen-kuo', '沈括', '存中', NULL, '[1031, 1095]', '公元1031年 — 1095年', 'male', '["科学家", "政治家", "博物学家", "梦溪笔谈作者"]', '读书百遍，其义自见', '沈括字存中，杭州钱塘人。北宋百科全书式科学家。曾任翰林学士司天监等职。著梦溪笔谈二十六卷，记录了他毕生的科学研究和见闻，涉及天文数学地理物理化学生物医药等各个领域。首创十二气历，发现磁偏角，研究光学声学地质学，是中国科学史上的里程碑。', '["梦溪笔谈", "科学家", "博学", "磁偏角", "天文"]', '["song-dynasty"]', '["bi-sheng"]'),
('song-yingxing', '宋应星', '长庚', NULL, '[1587, 1666]', '公元1587年 — 约1666年', 'male', '["科学家", "农学家", "天工开物作者"]', '天覆地载，物数号万，而事亦因之', '宋应星字长庚，奉新建县人。明朝杰出科学家。崇祯举人，曾任江西分宜教谕。著天工开物十五卷，系统总结了明代农业手工业生产技术，涵盖冶金纺织制瓷造纸食品加工等三十六个生产部门。被誉为中国十七世纪的工艺百科全书，被译成多国文字，对世界文明产生深远影响。', '["天工开物", "工艺", "农业", "手工业", "科学"]', '["ming-dynasty"]', '[]'),
('hua-mulan', '花木兰', '', NULL, '[500, 600]', '约公元四世纪', 'female', '["女英雄", "战士", "民间传奇人物"]', '将军百战死，壮士十年归', '花木兰，南北朝时期北方民间传奇女英雄。据木兰辞记载，她因父亲年老弟年幼，毅然女扮男装代父从军。征战十二年屡立战功，可汗赏赐高官却拒不受，愿驰千里足还故乡。回到家中恢复女装，同行战友皆惊愕。其故事被改编为戏曲诗歌电影，成为中国女性英雄的象征。', '["代父从军", "木兰辞", "女英雄", "民间传奇"]', '[]', '[]'),
('cai-wenji', '蔡文姬', '文姬', NULL, '[177, 249]', '公元177年 — 约249年', 'female', '["女诗人", "音乐家", "学者", "才女"]', '胡笳十八拍，声声泣鬼神', '蔡文姬名琰字文姬，陈留圉人，东汉大学者蔡邕之女。博学有才辩，通文学善音律。兴平年间战乱被掳匈奴十二年，嫁左贤王生二子。建安十三年曹操念其父无后，以金璧将她赎回。著悲愤诗述其坎坷经历，又作胡笳十八拍为琴曲。归汉后整理父亲遗书四千余篇，为中国文化保存了大量典籍。', '["才女", "胡笳十八拍", "蔡邕", "文学", "音乐"]', '["han-establish"]', '[]'),
('li-qingzhao', '李清照', '易安', NULL, '[1084, 1155]', '公元1084年 — 约1155年', 'female', '["婉约词宗", "女诗人", "文学评论家", "千古第一才女"]', '生当作人杰，死亦为鬼雄', '李清照号易安居士，济南人。中国文学史上最伟大的女词人。父李格进为苏轼学生，夫赵明诚为金石学家。早年生活优裕，与夫共同致力于书画金石的搜集整理。靖康之变后南渡，赵明诚病死，文物散失。晚年孤寂，著金石录后序述其坎坷。词分前期清新明丽后期沉郁凄凉，开创易安体，与辛弃疾并称济南二安。', '["婉约词", "漱玉词", "金石录", "易安居士", "才女"]', '["jingkang", "song-dynasty"]', '[]'),
('liang-hongyu', '梁红玉', '', NULL, '[1102, 1135]', '公元1102年 — 1135年', 'female', '["女英雄", "抗金名将", "巾帼英雄"]', '擂鼓战金山，威震敌胆', '梁红玉，淮安人，南宋抗金女英雄。原为乐籍，后嫁韩世忠为妻。建炎四年金兀术率大军南下，韩世忠截击黄天荡，梁红玉亲自披甲执桴擂鼓，士气大振，以八百大破金兵十万。后金兵绕道逃脱，但此战彰显巾帼不让须眉之气概。其事迹被后世广为传颂，成为中国历史上最著名的女性将领之一。', '["黄天荡", "擂鼓抗金", "韩世忠", "巾帼英雄"]', '["yue-fei"]', '["yue-fei"]'),
('shang-yang', '商鞅', '', NULL, '[-390, -338]', '约公元前390年 — 前338年', 'male', '["改革家", "法家代表人物", "政治家"]', '治世不一道，便国不法古', '商鞅原名卫鞅，公孙氏，战国初期卫国公子。好刑名之学，入秦后说服秦孝公变法。立木为信取信于民，推行废井田开阡陌奖励耕战实行连坐法等一系列改革。十年之后秦国大治，兵强天下。孝公死后遭贵族诬陷，兵败被杀，车裂而死。但其变法奠定了秦国统一六国的基础。', '["商鞅变法", "法治", "强国", "秦统一"]', '["shang-yang-bianfa", "qin-unify"]', '[]'),
('zhuge-liang', '诸葛亮', '孔明', NULL, '[181, 234]', '公元181年 — 234年', 'male', '["丞相", "政治家", "军事家", "发明家", "千古名相"]', '鞠躬尽瘁，死而后已', '诸葛亮字孔明号卧龙，琅琊阳都人。三国时期蜀汉丞相。隐居隆中，刘备三顾茅庐请出山。联吴抗曹，赤壁之战大败曹操。取益州定汉中，建立蜀汉基业。后辅佐刘禅，五次北伐曹魏。发明木牛流马孔明灯八阵图。出师表感人至深，被后世尊为忠臣楷模。杜甫赞曰：三顾频烦天下计，两朝开济老臣心。', '["隆中对", "出师表", "空城计", "木牛流马", "卧龙"]', '["three-kingdoms", "chi-bi"]', '[]'),
('wang-anshi', '王安石', '介甫', NULL, '[1021, 1086]', '公元1021年 — 1086年', 'male', '["改革家", "文学家", "政治家", "唐宋八大家"]', '天变不足畏，祖宗不足法，人言不足恤', '王安石字介甫号半山，抚州临川人。北宋著名政治家文学家。庆历进士，神宗时任宰相，主持熙宁变法。推行青苗法免役法方田均税法市易法等，旨在富国强兵。遭司马光等保守派强烈反对，两度罢相。其散文雄健峭拔，诗风清峭，著临川先生文集。位列唐宋八大家之一。', '["熙宁变法", "青苗法", "文学家", "唐宋八大家"]', '["song-dynasty"]', '[]'),
('zhang-juzheng', '张居正', '叔大', NULL, '[1525, 1582]', '公元1525年 — 1582年', 'male', '["政治家", "改革家", "内阁首辅", "万历元辅"]', '天下之事，不难于立法而难于法之必行', '张居正字叔大号太岳，江陵人。明朝万历年间内阁首辅。十载入阁，两年拜相，执政十年推行考成法整顿吏治，一条鞭法改革赋税，任用戚继光练兵潘季驯治河。使明朝出现万历中兴局面。死后被劾抄家，其改革措施大多被废。然其功过自有后人评说，梁启超誉之为中国二千年来内阁首辅中最有才干者。', '["一条鞭法", "考成法", "万历中兴", "内阁首辅"]', '["ming-dynasty"]', '[]'),
('li-hongzhang', '李鸿章', '少荃', NULL, '[1823, 1901]', '公元1823年 — 1901年', 'male', '["外交家", "政治家", "军事家", "洋务运动领袖"]', '我诚无力，理直安用', '李鸿章字少荃号仪叟，合肥人。晚清重臣，淮军创始人。协助曾国藩办洋务，组建淮军镇压太平天国。主持洋务运动三十年，创办江南制造总局轮船招商局北洋水师等。出使欧美，签订中日马关条约辛丑条约等多个不平等条约，被视为卖国贼。然其实为晚清柱石，在内外交困中勉力维持大局。', '["洋务运动", "淮军", "北洋水师", "晚清重臣"]', '["yangwu", "geng-zi-tiao-yue"]', '[]'),
('wang-xi-zhi', '王羲之', '逸之', NULL, '[303, 361]', '公元303年 — 361年', 'male', '["书圣", "书法家", "文学家", "右军将军"]', '飘若浮云，矫若惊龙', '王羲之字逸之，琅琊临沂人，后居会稽山阴。中国最伟大的书法家，世称王右军。七岁善书，幼时向卫夫人学书。后博采众长备精诸体，自成一家。书法精研体势草隶正行无所不精，开创妍美流畅的新书风。兰亭集序被誉为天下第一行书，唐太宗李世民极度推崇，命人摹刻分赐皇族近臣。', '["兰亭序", "书圣", "入木三分", "王献之"]', '["ji-qi", "cao-xue-qin"]', '[]'),
('wu-daozi', '吴道子', '道玄', NULL, '[680, 759]', '约公元680年 — 759年', 'male', '["画圣", "画家", "宗教画大师"]', '吴带当风', '吴道子又名道玄，阳翟人。唐朝最伟大的画家，被尊为画圣。曾为翰林院待诏，师张僧繇。擅佛道神仙人物画，创莼菜条状线描技法，衣带飘举故称吴带当风。长安洛阳寺观中壁画多达三百余堵，三周年内完成嘉陵江三百里山水画卷。代表作送子天王图为中国美术史珍贵遗产。', '["画圣", "吴带当风", "宗教画", "嘉陵江"]', '["tang-dynasty"]', '[]'),
('gu-kaizhi', '顾恺之', '长康', NULL, '[348, 409]', '约公元348年 — 409年', 'male', '["画家", "文学家", "画论家", "痴绝才绝艺绝"]', '传神写照，正在阿堵中', '顾恺之字长康，小字虎头，无锡人。东晋杰出画家，提出以形写神迁想妙得等绘画理论。擅人物肖像风景画，代表作洛神赋图根据曹植洛神赋创作，线条连绵不断如春蚕吐丝。又作女史箴图劝诫宫廷妇女。三绝才绝画绝痴绝，痴指其婚后可将食蜜粘须的趣事。为中国绘画理论奠基人之一。', '["洛神赋图", "女史箴图", "传神", "以形写神"]', '["ji-qi", "cao-xue-qin"]', '[]'),
('yan-li-ben', '阎立本', '', NULL, '[601, 673]', '约公元601年 — 673年', 'male', '["画家", "政治家", "宰相", "人物肖像画大师"]', '步辇图绘文成公主和亲事', '阎立本，雍州万年人。唐初著名画家兼政治家。父兄皆为绘画名家，自幼承家学。官至右丞相，故又称阎相国。擅人物肖像画，代表作步辇图描绘唐太宗接见吐蕃求婚使臣禄东赞场景，见证文成公主和亲历史。又作历代帝王图描绘十位帝王形象，笔法刚劲设色沉着，为中国人物画典范。', '["步辇图", "历代帝王图", "和亲", "宰相画家"]', '["tang-dynasty", "zhenguan-zhi"]', '["tang-taizong"]'),
('liu-gongquan', '柳公权', '诚悬', NULL, '[778, 865]', '公元778年 — 865年', 'male', '["书法家", "政治家", "柳体创始人"]', '心正则笔正', '柳公权字诚悬，京兆华原人。唐朝著名书法家，与颜真卿并称颜柳，有颜筋柳骨之美誉。十二岁能文，二十岁进士及第。书法初学王羲之，后融汇颜真卿自成一家。其楷书骨力遒劲结构严谨，世称柳体。穆宗问笔法，对曰心正则笔正，以书法喻谏君德，堪称字如其人。代表作玄秘塔碑神策军碑为后世学书范本。', '["柳体", "骨力", "颜筋柳骨", "玄秘塔碑"]', '["tang-dynasty"]', '["wang-xi-zhi"]'),
('mozi', '墨子', '翟', NULL, '[-470, -391]', '约公元前470年 — 约公元前391年', 'male', '["墨家创始人", "思想家", "科学家", "工匠"]', '兼相爱，交相利', '墨子名翟，战国初期宋国人（一说鲁国人）。墨家学派创始人，提出兼爱、非攻、尚贤、尚同、节用、非命、明鬼、天志、非乐、备城门等十大主张。与儒家并称''显学''。墨子还是科学家，在光学、力学、几何学方面有深入研究，发现小孔成像原理。', '["兼爱", "非攻", "墨家", "小孔成像", "备城门"]', '["spring-autumn"]', '["confucius", "mencius"]'),
('han-feizi', '韩非子', '', NULL, '[-280, -233]', '约公元前280年 — 公元前233年', 'male', '["法家集大成者", "思想家", "政治家"]', '法不阿贵，绳不挠曲', '韩非，韩国公子，与李斯同为荀子弟子。口吃不善言辞而善著书，著有五十二篇。融合商鞅的法、申不害的术、慎到的势，创立法家集大成思想。主张以法治国，严刑峻法，强化君主集权。其思想为秦始皇统一天下提供理论基础。后入秦被李斯陷害，服毒自尽。', '["法家", "法治", "君主集权", "五蠹", "孤愤"]', '["qin-unify", "shang-yang-bianfa"]', '["qin-shi"]'),
('wang-yangming', '王阳明', '伯安', NULL, '[1472, 1529]', '公元1472年 — 1529年', 'male', '["心学宗师", "思想家", "军事家", "政治家"]', '知行合一', '王阳明名守仁，字伯安，号阳明，浙江余姚人。明代最伟大的思想家之一。龙场悟道后创立心学体系，提出''知行合一''''致良知''的核心思想。军事上平定宁王之乱、南赣匪患，用兵如神。其学说影响中国、日本、朝鲜数百年，被誉为''立德立功立言''三不朽圣人。', '["心学", "知行合一", "致良知", "龙场悟道", "阳明学派"]', '["ming-dynasty"]', '["zhang-juzheng"]'),
('wang-wei', '王维', '摩诘', NULL, '[701, 761]', '公元701年 — 761年', 'male', '["诗佛", "画家", "音乐家", "诗人"]', '行到水穷处，坐看云起时', '王维字摩诘，河东蒲州人。唐代著名诗人、画家。精通诗文书画音乐，苏轼评价其''诗中有画，画中有诗''。与孟浩然合称''王孟''，为山水田园诗派代表。官至尚书右丞，世称''王右丞''。安史之乱中被俘迫受伪职，乱平后获赦。晚年隐居辋川，笃信佛教。', '["诗佛", "山水田园", "诗中有画", "辋川", "佛教"]', '["tang-dynasty"]', '["libai", "dufu"]'),
('bai-juyi', '白居易', '乐天', NULL, '[772, 846]', '公元772年 — 846年', 'male', '["诗人", "文学家", "地方官", "新乐府运动领袖"]', '同是天涯沦落人，相逢何必曾相识', '白居易字乐天，号香山居士，太原人。唐代三大诗人之一。与新乐府运动领袖，主张文章合为时而著，歌诗合为事而作。代表作有长恨歌琵琶行卖炭翁等。其诗通俗易懂，相传老妪能解。晚年与刘禹锡并称刘白，作品收录白氏长庆集。', '["长恨歌", "琵琶行", "新乐府", "香山居士", "现实主义"]', '["tang-dynasty", "an-shi"]', '["libai", "dufu"]'),
('han-xin', '韩信', '', NULL, '[-231, -196]', '约公元前231年 — 公元前196年', 'male', '["兵仙", "军事家", "淮阴侯"]', '多多益善', '韩信淮阴人，西汉开国功臣，中国历史上最杰出的军事家之一。早年家贫，漂母饭之。胯下之辱隐忍不发。投项羽不被用，转投刘邦。萧何月下追韩信，拜为大将。明修栈道暗度陈仓，背水一战井陉之战，潍水之战灭楚。功高震主，最终被吕后诛杀于长乐宫。', '["背水一战", "明修栈道", "萧何月下追韩信", "十面埋伏", "功高震主"]', '["han-establish", "bai-deng-hui"]', '["liu-bang"]'),
('wang-zhaojun', '王昭君', '嫱', NULL, '[-52, -15]', '约公元前52年 — 约公元前15年', 'female', '["和亲女性", "美女", "民族友好使者"]', '一去紫台连朔漠，独留青冢向黄昏', '王昭君名嫱，南郡秭归人。汉元帝时入宫，因不肯贿赂画师毛延寿而被丑化，多年不得见帝。匈奴呼韩邪单于来朝请求和亲，昭君主动请行。嫁呼韩邪单于后促成汉匈半个多世纪和平。其墓被称为青冢，成为民族团结的象征。', '["昭君出塞", "和亲", "汉匈和平", "青冢", "四大美女"]', '["han-establish", "bai-deng-hui"]', '[]'),
('guo-shou-jing', '郭守敬', '若思', NULL, '[1231, 1316]', '公元1231年 — 1316年', 'male', '["天文学家", "水利专家", "数学家", "仪器制造家"]', '历之本在于测验，测验之具莫先于仪表', '郭守敬字若思，邢台人。元代最伟大的科学家。主持修订授时历，测定一年为365.2425日，与现代值仅差26秒。建造简仪、仰仪、浑仪等天文仪器十余种。主持全国范围的大一统大地测量，子午线一度的弧长数据领先世界数百年。治理河渠，开通惠河连通大都与通州。', '["授时历", "简仪", "天文测量", "水利工程", "邢台"]', '["yuan-dynasty"]', '[]'),
('cao-cao', '曹操', '孟德', NULL, '[155, 220]', '公元155年 — 220年', 'male', '["政治家", "军事家", "文学家", "魏武帝"]', '老骥伏枥，志在千里', '曹操字孟德，沛国谯县人。东汉末年杰出的政治家、军事家、文学家。统一北方，推行屯田，唯才是举。官渡之战以少胜多击败袁绍。文学上开创建安风骨，短歌行观沧海等诗篇流传千古。死后其子曹丕称帝，追尊为武王。', '["官渡之战", "建安风骨", "唯才是举", "屯田制", "魏武帝"]', '["three-kingdoms", "chi-bi"]', '["zhuge-liang", "sun-quan"]'),
('si-ma-yi', '司马懿', '仲达', NULL, '[179, 251]', '公元179年 — 251年', 'male', '["军事家", "政治家", "晋朝奠基者"]', '鸟之将死，其鸣也哀', '司马懿字仲达，河内温县人。三国时期曹魏杰出军事家、政治家。对抗诸葛亮北伐，坚守不战消耗蜀军。平定公孙渊，高平陵之变夺取曹魏大权。其子孙司马炎建立晋朝，追尊为宣帝。善用兵，以奇谋著称，被后世誉为''古今良将''。', '["高平陵之变", "诸葛亮", "五丈原", "晋朝奠基", "奇谋"]', '["three-kingdoms", "ji-qi"]', '["zhuge-liang", "cao-cao"]'),
('sun-quan', '孙权', '仲谋', NULL, '[182, 252]', '公元182年 — 252年', 'male', '["吴大帝", "政治家", "军事家"]', '生子当如孙仲谋', '孙权字仲谋，吴郡富春人。三国时期东吴开国皇帝。继承父兄基业，任用周瑜鲁肃吕蒙陆逊等名将，在赤壁之战中大败曹操，奠定三分格局。称帝后开发江南，派卫温到达夷洲（今台湾）。在位二十四年，为三国在位最久之主。', '["赤壁之战", "夷洲", "开发江南", "吴大帝", "三分天下"]', '["three-kingdoms", "chi-bi"]', '["cao-cao", "zhuge-liang"]'),
('xiao-he', '萧何', '', NULL, '[-257, -193]', '约公元前257年 — 公元前193年', 'male', '["政治家", "相国", "功人"]', '镇国家，抚百姓，给馈饷，不绝粮道', '萧何沛县人，西汉开国第一功臣。秦时为沛县主吏掾，最早发现刘邦异于常人。楚汉战争中留守关中，为刘邦提供兵员粮饷。制定九章律，建立汉朝制度。论功第一，封酂侯，位列十二诸侯。司马迁评其''镇国家抚百姓，常主计'', 萧何月下追韩信识人善任。', '["九章律", "萧何月下追韩信", "功人", "酂侯", "开国第一功臣"]', '["han-establish", "chi-bi"]', '["han-xin"]'),
('huo-guang', '霍光', '', NULL, '[-14, -68]', '约公元前14年 — 公元前68年', 'male', '["政治家", "大司马", "辅政三朝"]', '明于治道，达于政理', '霍光字子孟，河东平阳人，霍去病异母弟。汉武帝临终任命为大司马大将军，辅佐昭帝宣帝三朝。昭帝时平定上官桀谋反，保持政局稳定。宣帝即位后废昌邑王刘贺，立汉宣帝，史称''霍光废立''。去世后被族灭，但其在汉昭宣中兴中功不可没。', '["昭宣中兴", "霍光废立", "大司马", "辅政三朝"]', '["han-establish", "wen-jing-zhi-zhi"]', '["huo-qubing"]'),
('li-si', '李斯', '', NULL, '[-280, -208]', '约公元前280年 — 公元前208年', 'male', '["政治家", "丞相", "法家代表"]', '仓鼠厕鼠之叹', '李斯楚国上蔡人，战国末期著名政治家。师从荀子学习帝王之术，入秦辅佐秦始皇。建议废分封行郡县，统一文字度量衡。反对焚书坑儒但未果。秦始皇死后与赵高合谋篡改遗诏，逼死扶苏。后被赵高陷害，腰斩于咸阳市，临刑前叹''欲与儿子牵黄犬出上蔡东门逐狡兔岂可得乎''。', '["郡县制", "统一文字", "谏逐客书", "沙丘之变", "腰斩"]', '["qin-unify", "shang-yang-bianfa"]', '["qin-shi"]'),
('zhuangzi', '庄子', '周', NULL, '[-369, -286]', '约公元前369年 — 公元前286年', 'male', '["道家代表", "思想家", "文学家"]', '吾生也有涯，而知也无涯', '庄子名周，宋国蒙人。继承和发展老子思想，与老子并称''老庄''。著有庄子三十三篇，主张逍遥齐物，追求精神自由。寓言故事丰富：庄周梦蝶、庖丁解牛、濠梁之辩、蜗角之争等。拒绝楚威王相位，宁愿''曳尾于涂中''。其思想对中国哲学文学艺术影响深远。', '["逍遥游", "齐物论", "庄周梦蝶", "庖丁解牛", "道家"]', '["spring-autumn"]', '["laozi", "mencius"]'),
('xun-zi', '荀子', '', NULL, '[-313, -238]', '约公元前313年 — 公元前238年', 'male', '["儒家大师", "思想家", "教育家"]', '人之性恶，其善者伪也', '荀子名况，字卿，赵国人。战国末期儒家最重要代表人物。主张性恶论，强调后天教育和礼法制度的重要性。游学齐国三为祭酒，后适楚春申君任兰陵令。弟子韩非李斯成为法家代表，可见其思想融通儒法。著有荀子三十二篇，涵盖哲学政治伦理等多个领域。', '["性恶论", "礼法并重", "天行有常", "兰陵", "儒法融合"]', '["spring-autumn", "qin-unify"]', '["confucius", "mencius", "han-feizi"]');
